INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Tercero Básico', 'Tecnologías del Aprendizaje y la Comunicación', '1. Comparte su experiencia, conocimientos, habilidades y conceptos tecnológicos con los demás.', ARRAY['1.1. Elige la herramienta y la plataforma apropiadas para transmitir sus ideas, trabajos o mensajes.', '1.2. Diseña materiales digitales como infografías, simulaciones, gráficos u otro material multimedia.', '1.3. Publica contenido en una estructura social compuesta de acuerdo con un criterio específico.']),
('Tercero Básico', 'Tecnologías del Aprendizaje y la Comunicación', '2. Crea recursos innovadores para proponer soluciones a problemas de la vida cotidiana desde el campo tecnológico, interactuando con expertos y miembros de la comunidad.', ARRAY['2.1. Utiliza aplicaciones tecnológicas para el análisis de datos, planificador digital, etc. que faciliten la propuesta de soluciones a un problema de carácter educativo o comunitario.', '2.2. Recolecta datos o identifica patrones relevantes mediante el uso de herramientas para la toma de decisiones.', '2.3. Comparte soluciones creativas utilizando texto, imágenes y video, de diferentes fuentes.']),
('Tercero Básico', 'Tecnologías del Aprendizaje y la Comunicación', '3. Interactúa socialmente en línea, respetando y aceptando las normas grupales.', ARRAY['3.1. Interactúa en la web de forma ética con personas de otras culturas, de forma que pueda ampliar su punto de vista y aprendizaje.', '3.2. Crea y comparte trabajos abordando problemas comunitarios en plataformas colaborativas.', '3.3. Explora problemas o necesidades de la comunidad y utiliza tecnología colaborativa para encontrar soluciones juntamente con sus compañeros y profesor.']);
